// Canary: Global RESTRICTED_SYNTAX_RULES_NEW — tests MethodDefinition-level rules
// Each section must trigger at least 1 ESLint error.

export class CanaryGlobal {
  public _data!: string; // 🚫 TYPE SKIP: Non-null assertion

  // Return Value Integrity (MethodDefinition — updated from TSMethodDefinition)
  public getNull(): null {
    return null;
  } // 🚫 null return + literal null
  public getVoid(): void {} // 🚫 void return forbidden
  public getUndefined(): undefined {
    return undefined;
  } // 🚫 undefined return

  // Nested call
  public run(): number {
    return Math.abs(Math.floor(1.5));
  } // 🚫 FORBIDDEN NESTED CALL

  // Unknown params/return + unknown variable
  public process(input: unknown): unknown {
    // 🚫 unknown param + return
    const data: unknown = input; // 🚫 unknown variable
    return data;
  }

  // Procedure discard
  public test(): boolean {
    this.record(); // 🚫 PROCEDURE: discarded result
    return true;
  }

  // Short alias
  public rename({ original: o }: { original: string }): string {
    return o;
  } // 🚫 OBFUSCATION

  private record(): { isSuccess: boolean } {
    return { isSuccess: true };
  }
}

// ForInStatement
for (const key in { a: 1 }) {
  String(key);
} // 🚫 ForInStatement banned

// Anti-sleep
const sleepResult = sleep(1000); // 🚫 sleep forbidden
const delayResult = delay(500); // 🚫 delay forbidden
export { sleepResult, delayResult };

declare function sleep(ms: number): Promise<boolean>;
declare function delay(ms: number): Promise<boolean>;

// Canary: Pipeline Section 6 guardrails — DI, mediator, result pattern, guard clauses
// Each section must trigger at least 1 Pipeline-specific ESLint error.

// 🚫 DI: Restricted import from Registry/Config
// (commented out — would break TSC, verified by import rule separately)
// import { SCRAPER_CONFIGURATION } from '../../../Registry/Config/ScraperConfig';

class CanaryHelper {}

export class CanaryPipeline {
  // 🚫 DI ENFORCEMENT: Manual instantiation (not in safe-list)
  public _helper = new CanaryHelper();

  // 🚫 RESULT PATTERN: Primitive return (string on MethodDefinition)
  public execute(): string {
    return 'done';
  }

  // 🚫 else blocks disallowed — use guard clauses
  public check(isOk: boolean): string {
    if (isOk) {
      return 'ok';
    } else {
      return 'fail';
    }
  }

  // 🚫 Ternary operators disallowed
  public mode(isDebug: boolean): string {
    return isDebug ? 'verbose' : 'silent';
  }

  // 🚫 PAGINATION: While loop forbidden
  public loop(): boolean {
    while (true) {
      break;
    }
    return true;
  }

  // 🚫 DATA INTEGRITY: '' fallback forbidden
  public fallback(val: string | false): string {
    const text = val || '';
    return text;
  }

  // 🚫 ARCHITECTURE: Status string comparison
  public isReady(status: string): boolean {
    return status === 'success';
  }

  // 🚫 catch clause .message access
  public safe(): string {
    try {
      return 'ok';
    } catch (err) {
      return (err as Error).message;
    }
  }

  // 🚫 as never / as any
  public cast(): string {
    const data = {} as never;
    return String(data);
  }
}

// Canary: TSAsExpression > TSNeverKeyword — as never/as any banned in tests
const mock = {} as never;
export { mock };

// Canary: ReturnStatement[argument=null] — bare return; must be caught
function earlyExit(): boolean {
  // @ts-expect-error Intentional: canary tests bare return
  return;
}
export { earlyExit };

// Canary: import-x/no-default-export — Pipeline must use named exports only
const value = 42;
export default value;
export { value };

