// Canary: IfStatement[alternate] — use guard clauses, not else
function withElse(x: boolean): string {
  if (x) {
    return 'yes';
  } else {
    return 'no';
  }
}
export { withElse };

// Canary: DI config literal — timeouts/dimensions must come from ctx.config
const options = { timeout: 5000 };
export { options };

// Canary: ReturnStatement > ObjectExpression — must use succeed()/fail()
function badReturn(): { success: boolean } {
  return { success: true };
}
export { badReturn };

// Canary: nested CallExpression — assign to descriptive variable first
function outer(x: number): number {
  return x;
}
function inner(): number {
  return 1;
}
const result = outer(inner());
export { result };

// Canary: Promise.any() ban — must use Promise.allSettled()
async function raceUnsafe(): Promise<number> {
  const result = await Promise.any([Promise.resolve(1)]);
  return result;
}
export { raceUnsafe };

// Canary: hardcoded status string — use Enums or Constants
function checkStatus(x: string): boolean {
  if (x === 'success') return true;
  return false;
}
export { checkStatus };

// Canary: ThrowStatement — Pipeline code must use Result Pattern, not throw
function crasher(): boolean {
  throw new Error('should use fail()');
}
export { crasher };

// Canary: void return type ban — functions must return meaningful values
function doNothing(): void {
  console.log('side effect');
}
export { doNothing };
